import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1. Browse the Sports category sorted by volume_24h
  const sportsMarkets = await callMcpSkill({
    toolId,
    toolName: "browse_category",
    args: {
      category: "Sports",
      sortBy: "volume_24h",
      limit: 5
    }
  });

  if (!sportsMarkets.markets || sportsMarkets.markets.length === 0) {
    return {
      error: "No active sports markets found.",
      category: "Sports"
    };
  }

  const topMarket = sportsMarkets.markets[0];

  // 2. Cross-reference the top result with Polymarket
  // Use both title and keywords for better matching
  const crossRef = await callMcpSkill({
    toolId,
    toolName: "kalshi_crossref_polymarket",
    args: {
      title: topMarket.title,
      keywords: topMarket.title,
      kalshiTicker: topMarket.ticker
    }
  });

  return {
    kalshiTopMarket: {
      title: topMarket.title,
      ticker: topMarket.ticker,
      yesPrice: topMarket.yesPrice, // in cents
      volume24h: topMarket.volume24h,
      url: topMarket.url
    },
    polymarketMatches: crossRef.polymarketResults || [],
    comparisonNote: crossRef.comparisonNote,
    fetchedAt: new Date().toISOString()
  };
}

